dict.string:
#!/bin/zsh

query="$1"
lastword="${query##* }"

# If user is actively typing a tag
if [[ "$lastword" == ::* ]]; then
  prefix="${lastword#::}"
  base="${query%$lastword}::"

  /usr/bin/osascript -l JavaScript <<EOF
  const of = Application("OmniFocus");
  const tags = of.defaultDocument.flattenedTags();
  const input = "$prefix".toLowerCase();
  const base = "$base";
  const results = tags
    .filter(t => t.name().toLowerCase().includes(input))
    .map(t => ({
      title: t.name(),
      subtitle: "🏷️ Choose a Tag",
      valid: false,
      autocomplete: base + t.name() + " "
    }));
  JSON.stringify({ items: results });
EOF
  exit 0

# If user is actively typing a project
elif [[ "$lastword" == '||'* ]]; then
  prefix="${lastword#'||'}"
  base="${query%$lastword}||"

  /usr/bin/osascript -l JavaScript <<EOF
  const of = Application("OmniFocus");
  const projects = of.defaultDocument.flattenedProjects();
  const input = "$prefix".toLowerCase();
  const base = "$base";
  const results = projects
    .filter(p => p.name().toLowerCase().includes(input))
    .map(p => ({
      title: p.name(),
      subtitle: "💼 Choose a Project",
      valid: false,
      autocomplete: base + p.name() + " "
    }));
  JSON.stringify({ items: results });
EOF
  exit 0
fi

# Default fallback – ready to create the task
cat <<EOF
{
  "items": [
    {
      "uid": "final-task",
      "title": "$query",
      "subtitle": "🚩!  ||💼  ::🏷️  #⏳  #⌛️  ~⏱️  //📝",
      "arg": "$query",
      "valid": true
    }
  ]
}
EOF

// GET ALL PROJECTS
const allProjects = Application("OmniFocus").defaultDocument.flattenedProjects()

// EXTRACT PROJECT DATA TO SCRIPT FILTER ITEMS
const sfItems = allProjects.map(project => {
	const projName = project.name()
	const projID = project.id()
	const taskCount = project.numberOfTasks()
	const remainTaskCount = taskCount - project.numberOfCompletedTasks()

	return {
		title: projName,
		subtitle: `${remainTaskCount} tasks remaining of ${taskCount}`,
		arg: projID
	}
})

// OUTPUT JSON
JSON.stringify({items:sfItems})

// GET ALL TAGS
const allTags = Application("OmniFocus").defaultDocument.flattenedTags()

// EXTRACT PROJECT DATA TO SCRIPT FILTER ITEMS
const sfItems = allTags.map(tag => {
	const tagName = tag.name()
	const tagID = tag.id()
	const remainTaskCount = tag.remainingTaskCount()

	return {
		title: tagName,
		subtitle: `${remainTaskCount} tasks remaining`,
		arg: tagID
	}
})

// OUTPUT JSON
JSON.stringify({items:sfItems})
